from zipline.api import order, get_open_orders, order_target

def handle_data(context, data):
    # Check for open orders before placing new ones
    open_orders = get_open_orders()
    if context.asset in open_orders:
        return  # Wait for pending orders to fill

    if context.signal > 0:
        order_target(context.asset, 100)
    elif context.signal < 0:
        order_target(context.asset, -100)
